/**
 * Represents an attribution item for a specific layer in the view.
 *
 * @since 5.0
 * @see [View.attributionItems](https://developers.arcgis.com/javascript/latest/references/core/views/View/#attributionItems)
 */
export default abstract class AttributionItem {
  /**
   * The score for this attribution item, which are displayed in descending order.
   *
   * @since 5.0
   */
  readonly score: number;
  /**
   * The text to display for this attribution item.
   *
   * @since 5.0
   */
  readonly text: string;
}